function walkDirectory(dir, depth) {
    if (depth === 0) return;
    const fs = require('fs');
    const dirContents = fs.readdirSync(dir);
    dirContents.forEach(file => {
        const filePath = dir + '/' + file;
        if (fs.statSync(filePath).isDirectory()) {
            walkDirectory(filePath, depth - 1);
        }
    });
}
